const items = $input.all();

for (let item of items) {
  const rawData = item.json;

  // Estructura Premium para el Dashboard
  item.json.categoria = (rawData.categoria || "CAT_VARIOS").startsWith('CAT_') ? rawData.categoria : ('CAT_' + (rawData.categoria || 'VARIOS').toUpperCase());
  item.json.plataforma = "TELEGRAM";
  item.json.ubicacion = rawData.ubicacion || "Madrid, ES";
  item.json.translations = {
    "es": { 
        "titulo": rawData.titulo_es || rawData.title || "Casting de Imagen", 
        "descripcion": rawData.desc_es || rawData.description || "" 
    },
    "en": { 
        "titulo": rawData.titulo_en || "Premium Casting", 
        "descripcion": rawData.desc_en || "Check details in the link below." 
    },
    "ru": { 
        "titulo": rawData.titulo_ru || "Премиум Кастинг", 
        "descripcion": rawData.desc_ru || "Подробности по ссылке ниже." 
    },
    "pt": { 
        "titulo": rawData.titulo_pt || "Casting Premium", 
        "descripcion": rawData.desc_pt || "Confira os detalhes no link abaixo." 
    }
  };
}

return items;
